const raw = $json.body || $json || {};
const headers = $json.headers || {};
const event = String(raw.event || 'operations.backup.requested');
const expectedWebhookToken = String($env.RS_CONNECT_N8N_WEBHOOK_TOKEN || '').trim();
const headerToken = String(headers['x-rs-connect-token'] || headers['X-RS-Connect-Token'] || '').trim();
const bearer = String(headers.authorization || headers.Authorization || '').replace(/^Bearer\s+/i, '').trim();
if (expectedWebhookToken && headerToken !== expectedWebhookToken && bearer !== expectedWebhookToken) {
  throw new Error('Token do webhook n8n invalido.');
}

if (event === 'operations.backup.ping') {
  return [{ json: { event, is_ping: true, routine_id: raw.routine_id || null } }];
}

const backup = raw.backup || {};
const callback = raw.callback || {};
const storagePath = String(backup.storage_path || '/backups/rs-connect').trim();
const database = String(backup.database || 'rs_connect').trim();
const retentionDays = Math.max(1, Math.min(365, Number(backup.retention_days || 5)));
const scriptPath = String($env.RS_CONNECT_BACKUP_SCRIPT || '/etc/easypanel/projects/sites/rsconnect/code/scripts/rsconnect-backup.sh').trim();
if (!/^\/[A-Za-z0-9._\/-]+$/.test(storagePath)) throw new Error('Caminho de backup invalido.');
if (!/^[A-Za-z0-9_]+$/.test(database)) throw new Error('Nome do banco invalido.');
if (!/^\/[A-Za-z0-9._\/-]+$/.test(scriptPath)) throw new Error('Caminho do script invalido.');
const quote = (value) => `'${String(value).replace(/'/g, `'\"'\"'`)}'`;
const sshCommand = `bash ${quote(scriptPath)} ${quote(storagePath)} ${retentionDays} ${quote(database)}`;
return [{ json: {
  ...raw,
  event,
  is_ping: false,
  routine_id: Number(raw.routine_id || raw.backup_routine_id || 0),
  backup_job_id: Number(raw.backup_job_id || 0),
  execution_uuid: String(raw.execution_uuid || ''),
  storage_type: String(backup.storage_type || 'server'),
  storage_path: storagePath,
  database,
  retention_days: retentionDays,
  ssh_command: sshCommand,
  callback_url: String(callback.url || $env.RS_CONNECT_BACKUP_CALLBACK_URL || ''),
  callback_token: String(callback.token || $env.RS_CONNECT_BACKUP_TOKEN || ''),
  requested_at: raw.requested_at || new Date().toISOString()
} }];

if ($json.is_ping) return [];
if (!$json.backup_job_id || !$json.callback_url || !$json.callback_token) {
  throw new Error('Job, callback URL e token sao obrigatorios.');
}
return items;

const source = $('Continuar somente backup').first().json;
const stdout = String($json.stdout || '').trim();
const stderr = String($json.stderr || $json.error || '').trim();
let result = null;
for (const line of stdout.split(/\r?\n/).reverse()) {
  if (!line.trim().startsWith('{')) continue;
  try { result = JSON.parse(line.trim()); break; } catch (_) {}
}
if (!result) {
  result = { status: 'error', verified: false, message: stderr || 'O script SSH nao retornou um resultado JSON valido.' };
}
const success = result.status === 'success' && result.verified === true;
const callbackPayload = {
  status: success ? 'success' : 'error',
  backup_type: 'automatic',
  storage_type: source.storage_type || 'server',
  routine_id: source.routine_id,
  backup_job_id: source.backup_job_id,
  execution_uuid: source.execution_uuid,
  file_name: result.file_name || null,
  location: result.location || null,
  size_bytes: Number(result.size_bytes || 0),
  checksum: result.checksum || '',
  verified: success,
  table_count: Number(result.table_count || 0),
  database: result.database || source.database,
  started_at: result.started_at || source.requested_at,
  finished_at: result.finished_at || new Date().toISOString(),
  notes: success ? `Backup concluido e validado (${Number(result.table_count || 0)} tabelas).` : String(result.message || stderr || 'Falha ao gerar backup.')
};
return [{ json: { callback_url: source.callback_url, callback_token: source.callback_token, callback_payload: callbackPayload } }];

const payload = $('Montar callback final').first().json.callback_payload || {};
if (String(payload.status || '') !== 'success') {
  throw new Error(String(payload.notes || 'Backup terminou com erro. Consulte o callback registrado no RS Connect.'));
}
return items;
